pragma solidity ^0.8.0;

contract HireChain {
    // Role enum
    enum Role { Employer, Freelancer }

    struct Project {
        uint256 id;
        string name;
        string description;
        address employer;
        address freelancer;
        uint256 bidAmount;
        bool completed;
        bool isFunded;
        uint256 timestamp;
    }

    struct Freelancer {
        address freelancerAddress;
        uint256 reputation;
    }

    mapping(uint256 => Project) public projects;
    mapping(address => Freelancer) public freelancers;
    mapping(uint256 => address[]) public projectFreelancers;
    uint256 public projectCount;

    // Add to your existing contract
    mapping(uint256 => uint256) public projectFunds; // Track funds for each project

    event FundsDeposited(uint256 projectId, address employer, uint256 bidAmount);
    event FundsReleased(uint256 projectId, address freelancer, uint256 bidAmount);

    event ProjectCreated(uint256 id, string name, string description, address employer);
    event ProjectCompleted(uint256 id, address employer, address freelancer, uint256 bidAmount);
    event ProjectApplied(uint256 id, address freelancer, uint256 bidAmount);
    
    

    function createProject(string memory _name, string memory _description) public {
        projectCount++;
        // Assign all 9 arguments as required by the Project struct
        projects[projectCount] = Project(
            projectCount,              // id
            _name,                     // name
            _description,              // description
            msg.sender,                // employer
            address(0),                // freelancer (initially set to address(0))
            0,                         // bidAmount
            false,                     // completed (default to false)
            false,                     // isFunded (default to false)
            block.timestamp            // timestamp
        );
        emit ProjectCreated(projectCount, _name, _description, msg.sender);
    }

    function depositFunds(uint256 _projectId) public payable {
        require(msg.sender == projects[_projectId].employer, "Only employer can deposit");
        require(msg.value > 0, "Funds must be greater than zero");

        projectFunds[_projectId] += msg.value;
        emit FundsDeposited(_projectId, msg.sender, msg.value);
    }

    function applyForProject(uint256 _projectId, uint256 _bidAmount) public {
        Project storage project = projects[_projectId];
        require(project.freelancer == address(0), "Project already has a freelancer");
        projectFreelancers[_projectId].push(msg.sender);
        emit ProjectApplied(_projectId, msg.sender, _bidAmount);
    }

    function markProjectAsCompleted(uint256 _projectId) public {
        Project storage project = projects[_projectId];
        require(msg.sender == project.employer, "Only employer can mark as completed");
        require(project.isFunded, "Project is not funded");
        project.completed = true;
    }

    function releaseFunds(uint256 _projectId) public {
        Project storage project = projects[_projectId];
        require(msg.sender == project.employer, "Only employer can release funds");
        require(project.completed, "Project must be marked as completed");
        require(project.freelancer != address(0), "Freelancer must be assigned");

        uint256 amount = projectFunds[_projectId];
        require(amount > 0, "No funds available for this project");

        projectFunds[_projectId] = 0;
        payable(project.freelancer).transfer(amount);
        emit FundsReleased(_projectId, project.freelancer, amount);
    }

    function getFreelancerReputation(address _freelancer) public view returns (uint256) {
        return freelancers[_freelancer].reputation;
    }

    function getFreelancers() public view returns (address[] memory) {
        address[] memory allFreelancers = new address[](projectCount);
        uint256 index = 0;
        for (uint256 i = 1; i <= projectCount; i++) {
            address[] memory freelancersInProject = projectFreelancers[i];
            for (uint256 j = 0; j < freelancersInProject.length; j++) {
                allFreelancers[index] = freelancersInProject[j];
                index++;
            }
        }
        return allFreelancers;
    }
}
